"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[11360],{33480:(e,n,i)=>{i.r(n),i.d(n,{data:()=>s});const s={key:"v-6c12bf07",path:"/C#/Winform/%E6%89%93%E5%BC%80%E5%A4%96%E9%83%A8%E7%A8%8B%E5%BA%8F.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"C#启动外部程序的几种常用方法汇总",slug:"c-启动外部程序的几种常用方法汇总",children:[]}],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/Winform/打开外部程序.md"}},65228:(e,n,i)=>{i.r(n),i.d(n,{default:()=>l});const s=(0,i(57293).uE)('<h3 id="c-启动外部程序的几种常用方法汇总" tabindex="-1"><a class="header-anchor" href="#c-启动外部程序的几种常用方法汇总" aria-hidden="true">#</a> C#启动外部程序的几种常用方法汇总</h3><p>转自:https://www.cnblogs.com/randyzhuwei/p/5403922.html</p><p>https://www.cnblogs.com/yangyangblog/p/10700159.html</p><h4 id="_1-启动外部程序-不等待其退出。" tabindex="-1"><a class="header-anchor" href="#_1-启动外部程序-不等待其退出。" aria-hidden="true">#</a> 1. 启动外部程序，不等待其退出。</h4><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>private string appName = &quot;calc.exe&quot;;\n/// &lt;summary&gt;\n/// 1. 启动外部程序，不等待其退出\n/// &lt;/summary&gt;\n/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;\n/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;\nprivate void button1_Click(object sender, EventArgs e)\n{\n    Process.Start(appName);\n    MessageBox.Show(String.Format(&quot;外部程序 {0} 启动完成！&quot;, this.appName), this.Text,\n    MessageBoxButtons.OK, MessageBoxIcon.Information);\n}\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-启动外部程序-等待其退出。" tabindex="-1"><a class="header-anchor" href="#_2-启动外部程序-等待其退出。" aria-hidden="true">#</a> 2. 启动外部程序，等待其退出。</h4><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>/// &lt;summary&gt;\n/// 2. 启动外部程序，等待其退出\n/// &lt;/summary&gt;\n/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;\n/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;\nprivate void button2_Click(object sender, EventArgs e)\n{\n    try\n    {\n        Process proc = Process.Start(appName);\n        if (proc != null)\n        {\n            proc.WaitForExit(3000);\n            if (proc.HasExited) MessageBox.Show(String.Format(&quot;外部程序 {0} 已经退出！&quot;, this.appName), this.Text,\n            MessageBoxButtons.OK, MessageBoxIcon.Information);\n            else\n            {\n                // 如果外部程序没有结束运行则强行终止之。\n                proc.Kill();\n                MessageBox.Show(String.Format(&quot;外部程序 {0} 被强行终止！&quot;, this.appName), this.Text, MessageBoxButtons.OK, MessageBoxIcon.Exclamation);\n            }\n        }\n    }\n    catch (ArgumentException ex)\n    {\n        MessageBox.Show(ex.Message, this.Text, MessageBoxButtons.OK, MessageBoxIcon.Error);\n    }\n}\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-启动外部程序-无限等待其退出。" tabindex="-1"><a class="header-anchor" href="#_3-启动外部程序-无限等待其退出。" aria-hidden="true">#</a> 3. 启动外部程序，无限等待其退出。</h4><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>/// &lt;summary&gt;\n/// 3. 启动外部程序，无限等待其退出\n/// &lt;/summary&gt;\n/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;\n/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;\nprivate void button3_Click(object sender, EventArgs e)\n{\n    try\n    {\n        Process proc = Process.Start(appName);\n        if (proc != null)\n        {\n            proc.WaitForExit();\n            MessageBox.Show(String.Format(&quot;外部程序 {0} 已经退出！&quot;, this.appName), this.Text,\n            MessageBoxButtons.OK, MessageBoxIcon.Information);\n        }\n    }\n    catch (ArgumentException ex)\n    {\n        MessageBox.Show(ex.Message, this.Text, MessageBoxButtons.OK, MessageBoxIcon.Error);\n    }\n}\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-启动外部程序-通过事件监视其退出。" tabindex="-1"><a class="header-anchor" href="#_4-启动外部程序-通过事件监视其退出。" aria-hidden="true">#</a> 4. 启动外部程序，通过事件监视其退出。</h4><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>/// &lt;summary&gt;\n/// 启动外部程序，通过事件监视其退出。\n/// &lt;/summary&gt;\n/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;\n/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;\nprivate void button4_Click(object sender, EventArgs e)\n{\n    try\n    {\n        //启动外部程序\n        Process proc = Process.Start(appName);\n        if (proc != null)\n        {\n            //监视进程退出\n            proc.EnableRaisingEvents = true;\n            //指定退出事件方法\n            proc.Exited += new EventHandler(proc_Exited);\n        }\n    }\n    catch (ArgumentException ex)\n    {\n        MessageBox.Show(ex.Message, this.Text, MessageBoxButtons.OK, MessageBoxIcon.Error);\n    }\n}\n\n/// &lt;summary&gt;\n///启动外部程序退出事件\n/// &lt;/summary&gt;\nvoid proc_Exited(object sender, EventArgs e)\n{\n    MessageBox.Show(String.Format(&quot;外部程序 {0} 已经退出！&quot;, this.appName), this.Text,\n    MessageBoxButtons.OK, MessageBoxIcon.Information);\n}\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_5-启动外部程序并传递参数" tabindex="-1"><a class="header-anchor" href="#_5-启动外部程序并传递参数" aria-hidden="true">#</a> 5.启动外部程序并传递参数</h4><p>第一个程序</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>try\n  {               \n       \n      ProcessStartInfo startInfo = new ProcessStartInfo();\n      startInfo.FileName = &quot;WindowsFormsApplication1.exe&quot;; //启动的应用程序名称\n      //Arguments 每个空格表示表示一个参数,当参数本身带有空格时,需要用&quot;&quot;包裹起来\n      startInfo.Arguments = &quot;\\&quot;我是由控制台程序传  过来的参数，如果传多个参数用空格隔开\\&quot;+&quot; \\&quot;第二个参数\\&quot;;\n      startInfo.WindowStyle = ProcessWindowStyle.Normal;\n      Process.Start(startInfo);\n   \n  }\n  catch (Exception ex)\n  {\n      throw;\n  }\n\n\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>第二个程序：</p><p>Program.cs 需要改Main方法</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>static class Program\n{\n    /// &lt;summary&gt;\n    /// 应用程序的主入口点。\n    /// &lt;/summary&gt;\n    [STAThread]\n   public  static void Main(string []args) //加参数，接收值\n    {\n        Application.EnableVisualStyles();\n        Application.SetCompatibleTextRenderingDefault(false);\n        if (args.Length == 0)\n        {\n            Application.Run(new Form1());\n        }\n        else\n        {\n            Application.Run(new Form1(args));\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Form1()窗口增加构造函数：</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>string[] args=null;\n       public Form1(string[] args)\n       {\n           InitializeComponent();\n         //this.ShowIcon = false;\n           this.ShowInTaskbar = false; //隐藏在系统任务栏\n           this.WindowState = FormWindowState.Minimized;\n          //this.FormBorderStyle = FormBorderStyle.SizableToolWindow;\n \n           this.args = args;\n       }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',19),a={},l=(0,i(63243).Z)(a,[["render",function(e,n){return s}]])},63243:(e,n)=>{n.Z=(e,n)=>{const i=e.__vccOpts||e;for(const[e,s]of n)i[e]=s;return i}}}]);